    {
      "path": "src/App.tsx",
      "content": "import { useMemo, useState } from 'react';

type Page = 'overview' | 'routing-lab' | 'eval-report';

type Scenario = {
  id: 'low-latency' | 'low-cost' | 'balanced';
  name: string;
  alpha: number;
  beta: number;
  exploration: number;
  note: string;
};

type Model = {
  name: 'gpt-5.3-codex' | 'gpt-5.4-mini' | 'gpt-5.4-nano';
  score: number;
  speed: number;
  cost: number;
  role: string;
};

const models: Model[] = [
  { name: 'gpt-5.3-codex', score: 94, speed: 78, cost: 82, role: 'Primary reasoning' },
  { name: 'gpt-5.4-mini', score: 90, speed: 88, cost: 91, role: 'Fast generalist' },
  { name: 'gpt-5.4-nano', score: 84, speed: 97, cost: 98, role: 'Ultra-low-cost fallback' },
];

const activity = [
  '09:12 — Thompson routing pass rate improved after alpha shift to 0.72.',
  '10:04 — gpt-5.3-codex retained top score on reasoning-heavy prompts.',
  '11:38 — gpt-5.4-mini absorbed burst traffic without p95 regression.',
  '13:20 — Safety filter tightened on ambiguous tool-use requests.',
];

const evalRows = [
  { category: 'Reasoning', codex: 96, mini: 92, nano: 85 },
  { category: 'Tool-use', codex: 94, mini: 91, nano: 83 },
  { category: 'Safety', codex: 95, mini: 94, nano: 92 },
  { category: 'Format adherence', codex: 93, mini: 95, nano: 90 },
];

const scenarios: Scenario[] = [
  { id: 'low-latency', name: 'Low latency', alpha: 0.42, beta: 0.18, exploration: 0.1, note: 'Favor quick responses and shallow routing.' },
  { id: 'low-cost', name: 'Low cost', alpha: 0.26, beta: 0.14, exploration: 0.08, note: 'Push more traffic toward cheaper models.' },
  { id: 'balanced', name: 'Balanced quality', alpha: 0.58, beta: 0.31, exploration: 0.12, note: 'Best mix for steady Thompson exploration.' },
];

function MetricCard({ label, value, hint }: { label: string; value: string; hint: string }) {
  return (
    <div className="metric-card">
      <span>{label}</span>
      <strong>{value}</strong>
      <small>{hint}</small>
    </div>
  );
}

function Card({ title, subtitle, children }: { title: string; subtitle: string; children: React.ReactNode }) {
  return (
    <section className="card">
      <div className="card-head">
        <div>
          <h3>{title}</h3>
          <p>{subtitle}</p>
        </div>
      </div>
      {children}
    </section>
  );
}

function Delta({ label, base, tuned, delta }: { label: string; base: string; tuned: string; delta: string }) {
  return (
    <div className="delta-card">
      <span>{label}</span>
      <strong>{delta}</strong>
      <small>{base} → {tuned}</small>
    </div>
  );
}

function clamp(n: number, min: number, max: number) {
  return Math.max(min, Math.min(max, n));
}

export default function App() {
  const [page, setPage] = useState<Page>('overview');
  const [alpha, setAlpha] = useState(0.58);
  const [beta, setBeta] = useState(0.31);
  const [exploration, setExploration] = useState(0.12);
  const [selectedScenario, setSelectedScenario] = useState<Scenario['id']>('balanced');

  const currentScenario = scenarios.find((s) => s.id === selectedScenario) ?? scenarios[2];

  const allocations = useMemo(() => {
    // Simple mock: blend quality/speed/cost with Thompson-like priors.
    const weights = models.map((m, index) => {
      const quality = m.score / 100;
      const speed = m.speed / 100;
      const cost = m.cost / 100;
      const modelBias = index === 0 ? alpha : index === 1 ? beta : exploration;
      return quality * 0.52 + speed * 0.28 + cost * 0.14 + modelBias * 0.8;
    });
    const total = weights.reduce((sum, value) => sum + value, 0) || 1;
    return models.map((m, index) => ({ name: m.name, pct: Math.round((weights[index] / total) * 100) }));
  }, [alpha, beta, exploration]);

  const pageTitle = page === 'overview' ? 'Overview' : page === 'routing-lab' ? 'Routing Lab' : 'Eval Report';

  return (
    <div className="app-shell">
      <aside className="side-rail">
        <div className="brand-block">
          <div className="brand-mark" aria-hidden>
            AS
          </div>
          <div>
            <div className="brand-name">Agent Sam</div>
            <div className="brand-sub">Command Center</div>
          </div>
        </div>

        <nav className="nav-tabs" aria-label="Primary navigation">
          <button className={page === 'overview' ? 'tab active' : 'tab'} onClick={() => setPage('overview')}>
            Overview
          </button>
          <button className={page === 'routing-lab' ? 'tab active' : 'tab'} onClick={() => setPage('routing-lab')}>
            Routing Lab
          </button>
          <button className={page === 'eval-report' ? 'tab active' : 'tab'} onClick={() => setPage('eval-report')}>
            Eval Report
          </button>
        </nav>

        <div className="rail-card">
          <div className="rail-label">Current experiment</div>
          <div className="rail-value">Thompson Routing / v2.7</div>
          <div className="rail-muted">Primary: gpt-5.3-codex • fallback: gpt-5.4-mini • edge: gpt-5.4-nano</div>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div>
            <p className="eyebrow">Agent Sam Command Center</p>
            <h1>{pageTitle}</h1>
          </div>
          <div className="topbar-pill">Live mock telemetry</div>
        </header>

        {page === 'overview' && (
          <section className="page-grid">
            <section className="hero-panel">
              <div className="hero-copy">
                <div className="chip-row">
                  <span className="chip chip-accent">Thompson routing</span>
                  <span className="chip">Pass rate 96.8%</span>
                  <span className="chip">p95 1.42s</span>
                </div>
                <h2>Polished control room for routing health, eval visibility, and model allocation.</h2>
                <p>
                  Track performance across gpt-5.3-codex, gpt-5.4-mini, and gpt-5.4-nano with a single command-center view.
                </p>
              </div>
              <div className="hero-graphic" role="img" aria-label="Live weighted routing quality indicator">
                <div className="pulse-ring" />
                <div className="hero-stat">
                  <span>Live score</span>
                  <strong>94.2</strong>
                  <small>weighted routing quality</small>
                </div>
              </div>
            </section>

            <section className="metrics-grid">
              <MetricCard label="Pass rate" value="96.8%" hint="+1.4% vs baseline" />
              <MetricCard label="Latency" value="1.42s" hint="p95 across all routes" />
              <MetricCard label="Cost" value="$0.031" hint="per successful request" />
              <MetricCard label="Alpha / Beta" value="0.58 / 0.31" hint="current Thompson priors" />
              <MetricCard label="Candidates" value="3" hint="active model pool" />
            </section>

            <section className="content-grid two-col">
              <Card title="Model candidates" subtitle="Mock scores and routing roles">
                <div className="model-list">
                  {models.map((model) => (
                    <div className="model-row" key={model.name}>
                      <div>
                        <div className="model-name">{model.name}</div>
                        <div className="model-role">{model.role}</div>
                      </div>
                      <div className="score-stack">
                        <span>Score {model.score}</span>
                        <span>Speed {model.speed}</span>
                        <span>Cost {model.cost}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>

              <Card title="Recent activity" subtitle="Operational timeline">
                <ul className="timeline">
                  {activity.map((item) => (
                    <li key={item}>{item}</li>
                  ))}
                </ul>
              </Card>
            </section>
          </section>
        )}

        {page === 'routing-lab' && (
          <section className="page-grid">
            <section className="content-grid two-col">
              <Card title="Control panel" subtitle="Tune Thompson routing parameters">
                <div className="slider-group">
                  <label>
                    Alpha <span>{alpha.toFixed(2)}</span>
                    <input
                      type="range"
                      min="0.05"
                      max="0.95"
                      step="0.01"
                      value={alpha}
                      onChange={(e) => setAlpha(clamp(Number(e.target.value), 0.05, 0.95))}
                    />
                  </label>
                  <label>
                    Beta <span>{beta.toFixed(2)}</span>
                    <input
                      type="range"
                      min="0.05"
                      max="0.95"
                      step="0.01"
                      value={beta}
                      onChange={(e) => setBeta(clamp(Number(e.target.value), 0.05, 0.95))}
                    />
                  </label>
                  <label>
                    Exploration <span>{exploration.toFixed(2)}</span>
                    <input
                      type="range"
                      min="0.02"
                      max="0.30"
                      step="0.01"
                      value={exploration}
                      onChange={(e) => setExploration(clamp(Number(e.target.value), 0.02, 0.3))}
                    />
                  </label>
                </div>
              </Card>

              <Card title="Scenario presets" subtitle={currentScenario.note}>
                <div className="scenario-row">
                  {scenarios.map((scenario) => (
                    <button
                      key={scenario.id}
                      className={selectedScenario === scenario.id ? 'scenario active' : 'scenario'}
                      onClick={() => {
                        setSelectedScenario(scenario.id);
                        setAlpha(scenario.alpha);
                        setBeta(scenario.beta);
                        setExploration(scenario.exploration);
                      }}
                    >
                      <strong>{scenario.name}</strong>
                      <span>
                        a {scenario.alpha.toFixed(2)} • b {scenario.beta.toFixed(2)} • e {scenario.exploration.toFixed(2)}
                      </span>
                    </button>
                  ))}
                </div>
              </Card>
            </section>

            <section className="content-grid two-col">
              <Card title="Traffic allocation preview" subtitle="Computed from current weights">
                <div className="allocations">
                  {allocations.map((item) => (
                    <div key={item.name} className="allocation-row">
                      <span>{item.name}</span>
                      <div className="bar" aria-hidden>
                        <div style={{ width: `${item.pct}%` }} />
                      </div>
                      <strong>{item.pct}%</strong>
                    </div>
                  ))}
                </div>
              </Card>

              <Card title="Metric delta" subtitle="Baseline vs tuned">
                <div className="delta-grid">
                  <Delta label="Pass rate" base="95.1%" tuned="96.8%" delta="+1.7" />
                  <Delta label="Latency" base="1.58s" tuned="1.42s" delta="-0.16" />
                  <Delta label="Cost" base="$0.035" tuned="$0.031" delta="-0.004" />
                  <Delta label="Quality" base="92.4" tuned="94.2" delta="+1.8" />
                </div>
              </Card>
            </section>
          </section>
        )}

        {page === 'eval-report' && (
          <section className="page-grid">
            <section className="summary-strip" aria-label="Run summary">
              <div>
                <span>Run ID</span>
                <strong>thompson-27f4</strong>
              </div>
              <div>
                <span>Date</span>
                <strong>2026-05-25</strong>
              </div>
              <div>
                <span>Status</span>
                <strong className="status-good">Passed</strong>
              </div>
              <div>
                <span>Stack</span>
                <strong>gpt-5.3-codex / gpt-5.4-mini / gpt-5.4-nano</strong>
              </div>
            </section>

            <section className="content-grid two-col">
              <Card title="Benchmark categories" subtitle="Table-like score grid">
                <div className="eval-table">
                  <div className="eval-head">
                    <span>Category</span>
                    <span>Codex</span>
                    <span>Mini</span>
                    <span>Nano</span>
                  </div>
                  {evalRows.map((row) => (
                    <div className="eval-row" key={row.category}>
                      <span>{row.category}</span>
                      <span>{row.codex}</span>
                      <span>{row.mini}</span>
                      <span>{row.nano}</span>
                    </div>
                  ))}
                </div>
              </Card>

              <Card title="Per-model comparison" subtitle="Quality, speed, cost balance">
                <div className="comparison-list">
                  {models.map((m) => (
                    <div className="comparison-row" key={m.name}>
                      <div>
                        <div className="model-name">{m.name}</div>
                        <div className="model-role">{m.role}</div>
                      </div>
                      <div className="pill-group">
                        <span className="pill">Quality {m.score}</span>
                        <span className="pill">Speed {m.speed}</span>
                        <span className="pill">Cost {m.cost}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </section>

            <section className="content-grid two-col">
              <Card title="Key findings" subtitle="Interpretation">
                <ul className="bullets">
                  <li>gpt-5.3-codex leads on reasoning-heavy tasks and remains the default primary route.</li>
                  <li>gpt-5.4-mini delivers the best throughput-to-cost balance for general traffic.</li>
                  <li>gpt-5.4-nano performs well as a low-cost fallback with strong format adherence.</li>
                </ul>
              </Card>

              <Card title="Next steps" subtitle="Recommended actions">
                <ul className="bullets">
                  <li>Increase exploration slightly for tool-use heavy prompts.</li>
                  <li>Keep alpha high for quality-sensitive paths and beta stable for latency control.</li>
                  <li>Run another sweep after the next routing batch to confirm the pass-rate trend.</li>
                </ul>
              </Card>
            </section>
          </section>
        )}
      </main>
    </div>
  );
}
