    {
      "path": "src/App.css",
      "content": ":root {
  color-scheme: dark;
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #0b1020;
  color: #e8edf7;
  line-height: 1.5;
  font-weight: 400;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: radial-gradient(circle at top, #17213a 0%, #0b1020 45%, #070b15 100%);
  color: #e8edf7;
}

button,
input {
  font: inherit;
}

button {
  cursor: pointer;
}

.app-shell {
  display: grid;
  grid-template-columns: 280px 1fr;
  min-height: 100vh;
}

.side-rail {
  padding: 24px;
  border-right: 1px solid rgba(255, 255, 255, 0.08);
  background: linear-gradient(180deg, rgba(18, 26, 43, 0.96), rgba(10, 15, 28, 0.92));
  backdrop-filter: blur(14px);
  position: sticky;
  top: 0;
  height: 100vh;
}

.brand-block,
.topbar,
.hero-panel,
.card,
.rail-card,
.metric-card,
.summary-strip {
  box-shadow: 0 16px 40px rgba(0, 0, 0, 0.24);
}

.brand-block {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 24px;
}

.brand-mark {
  width: 46px;
  height: 46px;
  border-radius: 14px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, #6ea8ff, #63e6be);
  color: #09111f;
  font-weight: 800;
}

.brand-name {
  font-size: 1.05rem;
  font-weight: 800;
}

.brand-sub {
  color: #9fb0cd;
}

.rail-muted,
.card-head p,
.metric-card small,
.delta-card small,
.topbar-pill,
.eval-row,
.eval-head,
.summary-strip span {
  color: #9fb0cd;
}

.nav-tabs {
  display: grid;
  gap: 10px;
}

.tab,
.scenario {
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(255, 255, 255, 0.03);
  color: #e8edf7;
  border-radius: 14px;
  padding: 14px 16px;
  text-align: left;
  transition: 0.2s ease;
}

.tab:hover,
.scenario:hover {
  transform: translateY(-1px);
  border-color: rgba(110, 168, 255, 0.35);
}

.tab.active,
.scenario.active {
  background: linear-gradient(135deg, rgba(110, 168, 255, 0.18), rgba(99, 230, 190, 0.14));
  border-color: rgba(110, 168, 255, 0.4);
}

.rail-card {
  margin-top: 24px;
  padding: 16px;
  background: rgba(18, 26, 43, 0.78);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 18px;
}

.rail-label {
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 0.72rem;
  color: #63e6be;
}

.rail-value {
  margin-top: 8px;
  font-weight: 700;
}

.main-content {
  padding: 24px;
}

.topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  padding: 18px 22px;
  border-radius: 20px;
  background: rgba(18, 26, 43, 0.75);
  border: 1px solid rgba(255, 255, 255, 0.08);
  margin-bottom: 22px;
}

.eyebrow {
  margin: 0 0 4px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  color: #63e6be;
  font-size: 0.75rem;
}

h1,
h2,
h3,
p {
  margin: 0;
}

h1 {
  font-size: 1.35rem;
}

.topbar-pill {
  white-space: nowrap;
  border-radius: 999px;
  padding: 8px 12px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.page-grid {
  display: grid;
  gap: 18px;
}

.hero-panel {
  display: grid;
  grid-template-columns: 1.4fr 0.8fr;
  gap: 20px;
  align-items: center;
  padding: 26px;
  border-radius: 24px;
  background: linear-gradient(
    135deg,
    rgba(110, 168, 255, 0.18),
    rgba(99, 230, 190, 0.08) 45%,
    rgba(18, 26, 43, 0.96)
  );
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.hero-copy h2 {
  margin: 14px 0 10px;
  font-size: clamp(1.6rem, 2.6vw, 3rem);
  line-height: 1.05;
}

.hero-copy p {
  max-width: 60ch;
  color: #bfd0ea;
}

.hero-graphic {
  min-height: 200px;
  border-radius: 24px;
  background: rgba(7, 11, 21, 0.35);
  display: grid;
  place-items: center;
  position: relative;
  overflow: hidden;
}

.pulse-ring {
  width: 140px;
  height: 140px;
  border-radius: 50%;
  border: 1px solid rgba(99, 230, 190, 0.35);
  box-shadow: 0 0 0 18px rgba(99, 230, 190, 0.06), 0 0 0 38px rgba(110, 168, 255, 0.05);
  animation: pulse 2.4s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    transform: scale(1);
    opacity: 1;
  }
  50% {
    transform: scale(1.04);
    opacity: 0.92;
  }
}

.hero-stat {
  position: absolute;
  text-align: center;
}

.hero-stat strong {
  display: block;
  font-size: 2.4rem;
}

.hero-stat span,
.hero-stat small {
  color: #9fb0cd;
}

.chip-row,
